829	/**
830	 * Helper function to perform the following:
831	 * ```python
832	 * x = attention_mask.long().cumsum(-1) - 1
833	 * x.masked_fill_(attention_mask == 0, 1)
834	 * ```
835	 * @param {Tensor} attention_mask
836	 * @returns {{data: BigInt64Array, dims: number[]}}
837	 */
838	function cumsum_masked_fill(attention_mask, start_index = 0) {
839	    const [bz, seq_len] = attention_mask.dims;
840	    const attn_mask_data = attention_mask.data;
841	
842	    const data = new BigInt64Array(attn_mask_data.length);
843	    for (let i = 0; i < bz; ++i) {
844	        const start = i * seq_len;
845	        let sum = BigInt(start_index);
846	        for (let j = 0; j < seq_len; ++j) {
847	            const index = start + j;
848	            if (attn_mask_data[index] === 0n) {
849	                data[index] = BigInt(1);
850	            } else { // === 1n
851	                data[index] = sum;
852	                sum += attn_mask_data[index];
853	            }
854	        }
855	    }
856	    return { data, dims: attention_mask.dims };
857	
858	}
