34	/**
35	 * Prompt with expanded image tokens for a single image.
36	 * @private
37	 */
38	function _prompt_single_image(image_seq_len, fake_token_around_image, image_token, global_img_token) {
39	    return (
40	        `${fake_token_around_image}` +
41	        `${global_img_token}` +
42	        image_token.repeat(image_seq_len) +
43	        `${fake_token_around_image}`
44	    );
45	}
46	
47	function get_image_prompt_string(image_rows, image_cols, image_seq_len, fake_token_around_image, image_token, global_img_token) {
48	    if (image_rows === 0 && image_cols === 0) {
49	        return _prompt_single_image(
50	            image_seq_len,
51	            fake_token_around_image,
52	            image_token,
53	            global_img_token
54	        );
55	    }
56	    return _prompt_split_image(
57	        image_seq_len, image_rows, image_cols, fake_token_around_image, image_token, global_img_token
58	    );
59	}
